#!/usr/bin/env python3
# Piece 1c-calfix (dream-os) — the date/day-counting cure, ported faithfully from
# dreamai (commit 364f854, which fixed BOTH Harvey and Donna).
#
# Two bugs, one root: the agents only had a bare ISO date, so they (a) guessed the
# YEAR (a March shoot landed on 2026, the past) and (b) couldn't COUNT days ("next
# Friday", "in 3 days") because nothing told them the weekday.
#
# The cure (dreamai today.ts): one clock line, read by BOTH souls so they never
# drift — weekday + human date + ISO ("Today is Thursday, 18 June 2026 (2026-06-18).").
# The weekday enables day-counting; the rule "every date resolves to the next
# occurrence, never a past date" fixes the year. Applied to Myra AND Kriya (the
# year was being decided in Myra's dispatch, one level above Kriya).
#
#   myraLoop.js   — todayLine() helper (port); full clock line in the UNCACHED
#                   today-block + the next-occurrence/no-past-date rule
#   kriyaTurn.js  — clock instruction reads the same full line; rule covers binder
#                   AND calendar dates
#   kriyaCalendar.js — tool desc nudged on year sense
#
# Caching untouched: the clock lives in the volatile/uncached block, by design.

import base64, os, sys
ROOT=os.getcwd()
PAYLOADS={
    'src/agent/myraLoop.js': '',
    'src/agent/kriyaTurn.js': '',
    'src/agent/kriyaCalendar.js': '',
}
def main():
    if not os.path.isdir(os.path.join(ROOT,"src","agent")):
        print("ERROR: run from dream-os repo root."); sys.exit(1)
    for rel,b64 in PAYLOADS.items():
        open(os.path.join(ROOT,rel),"wb").write(base64.b64decode(b64)); print(f"OK: overwrote {rel}")
    print("\nPiece 1c-calfix written. Both souls read one full clock line — year + day-counting cured.")
if __name__=="__main__": main()
